import{c as a,Q as s,j as n,m as i}from"./chunks/framework.BBA2dIOt.js";const h=JSON.parse('{"title":"Architecture","description":"","frontmatter":{},"headers":[],"relativePath":"architecture.md","filePath":"architecture.md","lastUpdated":1779898617000}'),l={name:"architecture.md"};function t(o,e,c,r,p,d){return s(),n("div",null,[...e[0]||(e[0]=[i(`<h1 id="architecture" tabindex="-1">Architecture <a class="header-anchor" href="#architecture" aria-label="Permalink to &quot;Architecture&quot;">​</a></h1><p>A reference for contributors. Covers process layout, request lifecycle, and how the major subsystems hand data off.</p><h2 id="process-layout" tabindex="-1">Process layout <a class="header-anchor" href="#process-layout" aria-label="Permalink to &quot;Process layout&quot;">​</a></h2><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>caddy ─┬─&gt; ember (Go binary)</span></span>
<span class="line"><span>       │     ├─ HTTP API + Fever shim + SPA serve</span></span>
<span class="line"><span>       │     ├─ Background poller (per-feed adaptive ticker)</span></span>
<span class="line"><span>       │     ├─ Summary worker pool (Ollama HTTP client)</span></span>
<span class="line"><span>       │     └─ DB maintenance goroutine (backup / cleanup / OPML / hourly)</span></span>
<span class="line"><span>       │</span></span>
<span class="line"><span>       └─&gt; SPA (embedded static files served by ember)</span></span>
<span class="line"><span></span></span>
<span class="line"><span>ollama  (sidecar) — model storage + inference</span></span></code></pre></div><p>The single <code>ember</code> binary embeds the Svelte SPA via <code>embed.FS</code> and serves it under <code>/</code>. The API is <code>/api/*</code>; mobile clients use <code>/fever</code>. The poller, summary worker, and maintenance goroutine all share the database via <code>internal/store</code>.</p><h2 id="package-map" tabindex="-1">Package map <a class="header-anchor" href="#package-map" aria-label="Permalink to &quot;Package map&quot;">​</a></h2><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>cmd/ember/                    main + probe subcommand + DB maintenance + digest sender</span></span>
<span class="line"><span>internal/api/                 chi router, handlers, middleware (CSRF, rate limit, auth context)</span></span>
<span class="line"><span>internal/auth/                argon2id passwords, securecookie sessions, WebAuthn (passkeys), RequireAuth/Admin middleware</span></span>
<span class="line"><span>internal/config/              env-var loading (typed Config)</span></span>
<span class="line"><span>internal/db/                  SQLite open, pragmas, embedded migrations (goose)</span></span>
<span class="line"><span>internal/digest/              SMTP daily-digest builder + sender (multipart/alt + STARTTLS)</span></span>
<span class="line"><span>internal/feed/                gofeed wrapper + readability fallback fetcher + Discover (homepage → feed URL)</span></span>
<span class="line"><span>internal/filters/             matcher (field/op/value), apply outcome combiner</span></span>
<span class="line"><span>internal/models/              data types shared across packages</span></span>
<span class="line"><span>internal/opml/                OPML import + export + discovery → subscribe</span></span>
<span class="line"><span>internal/poller/              adaptive scheduler, fetch dispatch, summary queue</span></span>
<span class="line"><span>internal/store/               SQLite CRUD, FTS5 search, app_settings KV, dbops, passkeys, digests</span></span>
<span class="line"><span>internal/summarize/           Summarizer interface + Ollama implementation + noop for tests</span></span>
<span class="line"><span>internal/sysinfo/             host-detection (RAM/CPU/GPU) + model recommendation</span></span>
<span class="line"><span>internal/urlcheck/            SSRF block (scheme allowlist + private-IP refusal)</span></span>
<span class="line"><span>internal/web/                 embed.FS handler for the SPA</span></span>
<span class="line"><span>web/                          Svelte 5 (runes) source; built via Vite, copied to internal/web/dist</span></span></code></pre></div><h2 id="database-schema" tabindex="-1">Database schema <a class="header-anchor" href="#database-schema" aria-label="Permalink to &quot;Database schema&quot;">​</a></h2><p>SQLite. Migrations in <code>internal/db/migrations/*.sql</code>, applied at startup. Key tables:</p><ul><li><code>users</code> — argon2id-hashed passwords; admin flag.</li><li><code>sessions</code> — server-side rows backing cookies; pruned periodically.</li><li><code>feeds</code> — shared across users; URL-unique. Tracks etag/last-modified/error counters.</li><li><code>subscriptions</code> — <code>(user_id, feed_id)</code> with category, title override, muted flag, and <code>position</code> for drag-reorder.</li><li><code>categories</code> — user-scoped folders with color + position.</li><li><code>articles</code> — shared across users; per-feed dedup by <code>guid</code> and <code>content_hash</code>. Carries <code>cleaned_html</code> (AI ad-stripped).</li><li><code>article_state</code> — per-user read/star/later flags.</li><li><code>articles_fts</code> — FTS5 virtual table on title/text/author; kept in sync via triggers.</li><li><code>boards</code> + <code>board_articles</code> — user-curated collections.</li><li><code>filters</code> — rule store; engine in <code>internal/filters</code>.</li><li><code>shares</code> — user-to-user article shares.</li><li><code>app_settings</code> — global KV (active model, schedules, branding, tuning).</li><li><code>saved_searches</code> — persisted FTS queries.</li><li><code>article_tags</code> — per-user tags on individual articles.</li><li><code>user_digests</code> — per-user opt-in daily-digest config (view, hour/minute UTC, last-sent timestamp).</li><li><code>passkeys</code> — WebAuthn credentials (credential_id, public_key, sign_count, name, timestamps).</li><li><code>webauthn_sessions</code> — short-lived ceremony state for in-flight register/login flows; reaped after 5 min.</li></ul><p>WAL mode, 64 MiB page cache, 256 MiB mmap, busy_timeout=5s. Single Go connection — writes are serialized (SQLite single-writer); reads are fast enough that the connection pool isn&#39;t the bottleneck at this scale.</p><h2 id="request-lifecycle" tabindex="-1">Request lifecycle <a class="header-anchor" href="#request-lifecycle" aria-label="Permalink to &quot;Request lifecycle&quot;">​</a></h2><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>HTTPS                Caddy</span></span>
<span class="line"><span>  └─&gt; :443  ──tls──&gt; ember:8080</span></span>
<span class="line"><span>                       │</span></span>
<span class="line"><span>                       ▼</span></span>
<span class="line"><span>                  chi.Router</span></span>
<span class="line"><span>                       │</span></span>
<span class="line"><span>        ┌──────────────┼──────────────┐</span></span>
<span class="line"><span>        ▼              ▼              ▼</span></span>
<span class="line"><span>   /api/auth/*    /api/*         /fever  (Fever shim)</span></span>
<span class="line"><span>                       │              │</span></span>
<span class="line"><span>                  CSRFVerify           │</span></span>
<span class="line"><span>                  RequireAuth          │</span></span>
<span class="line"><span>                  (RequireAdmin)       │</span></span>
<span class="line"><span>                       │              │</span></span>
<span class="line"><span>                       ▼              ▼</span></span>
<span class="line"><span>                   handlers       fever_handlers</span></span>
<span class="line"><span>                       │              │</span></span>
<span class="line"><span>                       └─&gt; store ─────┘</span></span>
<span class="line"><span>                              │</span></span>
<span class="line"><span>                              ▼</span></span>
<span class="line"><span>                          SQLite (WAL)</span></span></code></pre></div><p>Browsers store a server-side session cookie + a CSRF cookie. State-changing routes (<code>POST/PATCH/DELETE</code>) must echo the CSRF cookie in <code>X-Ember-CSRF</code>.</p><h2 id="poller-state-machine" tabindex="-1">Poller state machine <a class="header-anchor" href="#poller-state-machine" aria-label="Permalink to &quot;Poller state machine&quot;">​</a></h2><p>Each feed has <code>next_fetch</code> (unix seconds) and an <code>error_count</code>. The poller:</p><ol><li>Every <code>EMBER_POLL_TICK</code> (default 60s): <code>Tick(ctx)</code> queries <code>FeedsDue</code> (next_fetch ≤ now).</li><li>Due feeds fan out across <code>EMBER_POLL_CONCURRENCY</code> worker goroutines.</li><li>Each worker calls <code>Fetcher.Fetch(url, etag, last_modified)</code>: <ul><li>304 → bookkeep last_fetched/next_fetch, error_count = 0.</li><li>2xx → parse with gofeed, optionally enrich short bodies via go-readability, upsert articles.</li><li>Error → increment error_count, schedule next try with exponential backoff (capped at <code>MaxInterval</code>).</li></ul></li><li>Newly-inserted articles enqueue on <code>summaryCh</code> (best-effort, drops on full).</li><li>Filters apply per-subscriber as articles land.</li></ol><p>The summary worker is a separate goroutine that drains <code>summaryCh</code>, calls Ollama, writes <code>summary</code> + <code>summary_model</code> + <code>cleaned_html</code>. Failures stamp <code>summary_model = &#39;skipped&#39;</code> so the article still surfaces in the UI.</p><p>Restart safety: <code>enqueuePendingSummaries</code> runs at startup and seeds the channel from any articles with empty <code>summary_model</code>.</p><h2 id="summarizer-pipeline" tabindex="-1">Summarizer pipeline <a class="header-anchor" href="#summarizer-pipeline" aria-label="Permalink to &quot;Summarizer pipeline&quot;">​</a></h2><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>poller.summarize ─&gt; Summarizer.Summarize(title, text)</span></span>
<span class="line"><span>                       │</span></span>
<span class="line"><span>                       ├─ Ollama: POST /api/generate</span></span>
<span class="line"><span>                       │   prompt = labeled &quot;SUMMARY: / POINTS: / CLEANED:&quot;</span></span>
<span class="line"><span>                       │   options = {temperature, top_p, num_ctx} from app_settings</span></span>
<span class="line"><span>                       │   timeout = 90s, one retry on transient error</span></span>
<span class="line"><span>                       │</span></span>
<span class="line"><span>                       └─&gt; parseResult(s):</span></span>
<span class="line"><span>                              parseLabeled → parseJSONObject → parseJSONArray</span></span>
<span class="line"><span>                              → line-based fallback</span></span>
<span class="line"><span>                              + cleanBullets (strip markers / inline markdown /</span></span>
<span class="line"><span>                                              prompt-echo / label prefixes)</span></span>
<span class="line"><span>                              + stripEmphasis (** __ * \` &quot; &#39;)</span></span>
<span class="line"><span>                              + cleanParagraph</span></span></code></pre></div><p>Active model + tunables held in <code>atomic.Value</code>/<code>atomic.Pointer</code> on the <code>Ollama</code> struct so the admin API can swap them without restarting.</p><h2 id="spa" tabindex="-1">SPA <a class="header-anchor" href="#spa" aria-label="Permalink to &quot;SPA&quot;">​</a></h2><ul><li>Svelte 5 with runes (<code>$state</code>, <code>$derived</code>, <code>$effect</code>, <code>$props</code>).</li><li>Vite 5 build, output copied to <code>internal/web/dist</code>, served via <code>embed.FS</code>.</li><li>Typed fetch client in <code>web/src/lib/api.ts</code> (throws <code>ApiError</code>).</li><li>Stores in <code>web/src/lib/stores.ts</code> for user, feeds, categories, boards, articles, themes, branding, new-article counter, etc.</li><li>30s auto-refresh poll while the tab is visible; SSE not used — REST polling is simpler and fits the cadence.</li><li>Service worker (<code>web/public/sw.js</code>) caches assets immutably and falls back to cached shell when offline.</li></ul><h2 id="admin-endpoints-admin-only" tabindex="-1">Admin endpoints (admin-only) <a class="header-anchor" href="#admin-endpoints-admin-only" aria-label="Permalink to &quot;Admin endpoints (admin-only)&quot;">​</a></h2><ul><li><code>GET /api/admin/llm</code> — detected hardware, recommendation, installed models, current model + options.</li><li><code>POST /api/admin/llm/model</code> / <code>…/pull</code> / <code>…/delete</code> / <code>…/options</code> — switch / pull / delete / tune.</li><li><code>GET /api/branding</code> (public) / <code>POST /api/admin/branding</code> (admin).</li><li><code>GET /api/admin/db</code> — size, page count, recent backups, schedules.</li><li><code>POST /api/admin/db/backup</code> / <code>…/cleanup</code> / <code>…/schedule</code> — manual + scheduled maintenance.</li><li><code>POST /api/feeds/resummarize-all</code> — re-process every article after a prompt change.</li><li><code>GET /api/admin/session</code> / <code>POST /api/admin/session/ttl</code> — server-wide session cookie lifetime.</li><li><code>GET /api/admin/settings</code> / <code>PATCH /api/admin/settings</code> — SMTP relay config + initial-backlog window. Overlays env-derived defaults at runtime; digest sender re-resolves every tick.</li><li><code>POST /api/admin/settings/email-test</code> — send a one-off diagnostic message through the live SMTP config.</li></ul><p>Auth-required (not admin-only):</p><ul><li><code>POST /api/articles/{id}/extract</code> — on-demand readability re-run for the reader pane&#39;s &quot;Re-extract&quot; button. Subject to the same SSRF check as the poller&#39;s automatic enrichment.</li></ul><h2 id="e2e" tabindex="-1">E2E <a class="header-anchor" href="#e2e" aria-label="Permalink to &quot;E2E&quot;">​</a></h2><p><code>web/e2e/*.spec.ts</code> (Playwright). The binary in <code>EMBER_TEST_MODE=1</code> seeds a deterministic admin + 1 feed + 12 articles with known content, so specs can assert on titles/excerpts directly. Axe-core runs against the major screens for WCAG 2.1 AA.</p>`,30)])])}const m=a(l,[["render",t]]);export{h as __pageData,m as default};
